async def execute(self, inputs):
    executed = inputs.get('executed_actions') or []
    if not isinstance(executed, list):
        executed = [executed]

    action_type = (inputs.get('action_type') or self.get_parameter('action_type', '') or '').strip()
    index = inputs.get('index')
    if index is None:
        index = self.get_parameter('index', 0)
    try:
        index = int(index)
    except Exception:
        index = 0

    match = None

    if action_type:
        for a in executed:
            if isinstance(a, dict) and a.get('type') == action_type:
                match = a
                break
        if match is None:
            self.log_error(f'No executed action of type "{action_type}" found')
    else:
        if 0 <= index < len(executed):
            candidate = executed[index]
            if isinstance(candidate, dict):
                match = candidate
            else:
                self.log_error(f'Executed action at index {index} is not a dict')
        elif len(executed) == 0:
            self.log_error('executed_actions is empty')
        else:
            self.log_error(f'Index {index} out of range (executed_actions has {len(executed)} entries)')

    found = match is not None
    action = match or {}
    info = action.get('info', {}) if isinstance(action, dict) else {}
    if not isinstance(info, dict):
        info = {}

    path = ''
    if isinstance(action, dict):
        for key in ('blend_path', 'fbx_path', 'abc_path', 'obj_path', 'gltf_path', 'usd_path', 'output_path'):
            val = action.get(key)
            if val:
                path = val
                break

    if found:
        self.log_info(f'Matched action type={action.get("type", "")}')

    await self.set_output('found', found)
    await self.set_output('action', action)
    await self.set_output('info', info)
    await self.set_output('path', path)
    await self.set_output('exec_out', True)
    return {'found': found, 'action': action, 'info': info, 'path': path}
